awk '
  /\\begin\{[a-zA-Z]+\}/ { match($0, /\\begin\{[a-zA-Z]+\}/); env=substr($0, RSTART+7, RLENGTH-8); stack[++top]=env; counts[env]++ }
  /\\end\{[a-zA-Z]+\}/   { match($0, /\\end\{[a-zA-Z]+\}/);   env=substr($0, RSTART+5, RLENGTH-6); if(stack[top]!=env){print "MISMATCH at line " NR ": expected end{" stack[top] "}, got end{" env "}"} top--; counts[env]-- }
  END { for(e in counts) if(counts[e]!=0) print "Unbalanced env " e ": " counts[e]; if(top>0) print "Open envs remaining: " top }
' blueprint/src/chapters/RiemannRoch_RationalCurveIso.tex
